-- ----------------------------
-- 16、定时任务调度日志表
-- ----------------------------
DROP TABLE IF EXISTS sys_job_log CASCADE;
CREATE TABLE "sys_job_log" (
  "job_log_id" bigint     not null GENERATED BY DEFAULT AS IDENTITY,
  "job_name" varchar(64)    not null,
  "job_group" varchar(64)    not null,
  "invoke_target" varchar(500)   not null,
  "job_message" varchar(500),
  "status" char(1)        default '0',
  "exception_info" varchar(2000)  default '',
  "start_time" timestamp,
  "end_time" timestamp,
  "create_time" timestamp,
  PRIMARY KEY ("job_log_id")
);
COMMENT ON TABLE "sys_job_log" IS '定时任务调度日志表';
COMMENT ON COLUMN "sys_job_log"."job_log_id" IS '任务日志ID';
COMMENT ON COLUMN "sys_job_log"."job_name" IS '任务名称';
COMMENT ON COLUMN "sys_job_log"."job_group" IS '任务组名';
COMMENT ON COLUMN "sys_job_log"."invoke_target" IS '调用目标字符串';
COMMENT ON COLUMN "sys_job_log"."job_message" IS '日志信息';
COMMENT ON COLUMN "sys_job_log"."status" IS '执行状态（0正常 1失败）';
COMMENT ON COLUMN "sys_job_log"."exception_info" IS '异常信息';
COMMENT ON COLUMN "sys_job_log"."start_time" IS '执行开始时间';
COMMENT ON COLUMN "sys_job_log"."end_time" IS '执行结束时间';
COMMENT ON COLUMN "sys_job_log"."create_time" IS '创建时间';

-- ----------------------------
-- 17、通知公告表
-- ----------------------------
DROP TABLE IF EXISTS sys_notice CASCADE;
CREATE TABLE "sys_notice" (
  "notice_id" int          not null GENERATED BY DEFAULT AS IDENTITY,
  "notice_title" varchar(50)     not null,
  "notice_type" char(1)         not null,
  "notice_content" bytea        default null,
  "status" char(1)         default '0',
  "create_by" varchar(64)     default '',
  "create_time" timestamp,
  "update_by" varchar(64)     default '',
  "update_time" timestamp,
  "remark" varchar(255)    default null,
  PRIMARY KEY ("notice_id")
);
COMMENT ON TABLE "sys_notice" IS '通知公告表';
COMMENT ON COLUMN "sys_notice"."notice_id" IS '公告ID';
COMMENT ON COLUMN "sys_notice"."notice_title" IS '公告标题';
COMMENT ON COLUMN "sys_notice"."notice_type" IS '公告类型（1通知 2公告）';
COMMENT ON COLUMN "sys_notice"."notice_content" IS '公告内容';
COMMENT ON COLUMN "sys_notice"."status" IS '公告状态（0正常 1关闭）';
COMMENT ON COLUMN "sys_notice"."create_by" IS '创建者';
COMMENT ON COLUMN "sys_notice"."create_time" IS '创建时间';
COMMENT ON COLUMN "sys_notice"."update_by" IS '更新者';
COMMENT ON COLUMN "sys_notice"."update_time" IS '更新时间';
COMMENT ON COLUMN "sys_notice"."remark" IS '备注';

